/**
 * Public endpoint backing the "Submit a correction" form on the
`/corrections` page (and the small CTA in the site footer of
every page). Persists the submission to the editor inbox so
the corrections workflow can triage and apply the fix per the
SLA in the page's published five-rule policy (typo: 24h,
factual: 7 days).

The endpoint is intentionally unauthenticated — any reader
should be able to flag an error without signing up — so abuse
defences live at the API edge: a same-origin Origin/Referer
allowlist, a per-IP fixed-window rate limit, and a server-side
honeypot field (`website`) that real browsers leave blank.
Submissions whose honeypot is filled in are silently accepted
(HTTP 204) but never persisted, so bots can't tell they were
rejected.

 * @summary Submit a reader-flagged correction
 */
export const getSubmitCorrectionUrl = () => {
  return `/api/corrections`;
};

