/**
 * Editor-only inbox of reader-submitted corrections produced by
the public `POST /corrections` form. Returns rows newest-first
(by `createdAt`) so an editor scanning the queue every morning
sees fresh submissions at the top, with the SLA clock derived
client-side from `createdAt`.

With `?status=` the list is filtered to a single workflow
state. The default is `new`, matching the typical "what came
in since I last checked" workflow. Pass `all` to disable the
filter.

 * @summary List reader-submitted corrections for the editor inbox
 */
export const getListEditorCorrectionsUrl = (
  params?: ListEditorCorrectionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/editor/corrections?${stringifiedParams}`
    : `/api/editor/corrections`;
};

export const listEditorCorrections = async (
  params?: ListEditorCorrectionsParams,
  options?: RequestInit,
): Promise<EditorCorrectionsList> => {
  return customFetch<EditorCorrectionsList>(
    getListEditorCorrectionsUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListEditorCorrectionsQueryKey = (
  params?: ListEditorCorrectionsParams,
) => {
  return [`/api/editor/corrections`, ...(params ? [params] : [])] as const;
};

export const getListEditorCorrectionsQueryOptions = <
  TData = Awaited<ReturnType<typeof listEditorCorrections>>,
  TError = ErrorType<void>,
>(
  params?: ListEditorCorrectionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listEditorCorrections>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListEditorCorrectionsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listEditorCorrections>>
  > = ({ signal }) =>
    listEditorCorrections(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listEditorCorrections>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListEditorCorrectionsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listEditorCorrections>>
>;
export type ListEditorCorrectionsQueryError = ErrorType<void>;

